mapper.select:
SELECT id, sku_id, spu_id, member_id, spu_name, member_nick_name, star, member_ip, create_time, show_status, spu_attributes, likes_count, reply_count, resources, content, member_icon, comment_type FROM pms_spu_comment
AND spu_id = #{req.spuId}
AND sku_id = #{req.skuId}
AND member_nick_name LIKE CONCAT('%', #{req.memberNickName}, '%')
AND show_status = #{req.showStatus}
AND star = #{req.star}
AND member_id = #{req.memberId}
AND comment_type = #{req.commentType}
ORDER BY create_time DESC, id DESC

SELECT spu_id AS spuId, COUNT(1) AS total, AVG(star) AS avgStar FROM pms_spu_comment WHERE show_status = 1 AND (comment_type IS NULL OR comment_type = 0) AND spu_id IN
#{id}
GROUP BY spu_id
